CREATE DATABASE CUSTOMER_ANALYSIS;

SELECT * FROM customertable LIMIT 10;

-- Q1. What is the total revenue generated by male and female customers ?
SELECT gender, SUM(purchase_amount) as REVENUE 
FROM customertable
GROUP BY gender;

-- Q2. which customer used discount but still spent more than the average purchase amount ?
SELECT customer_id, purchase_amount
from customertable
WHERE discount_applied ="Yes" and purchase_amount>(SELECT AVG(purchase_amount) FROM customertable);

-- Q3. which are the top 5 products with highest average review rating?
SELECT item_purchased, ROUND(avg(review_rating),2) as "average product rating"
FROM customertable
GROUP BY item_purchased
ORDER BY AVG(review_rating) DESC
LIMIT 5;

-- Q4. Compare average purchase amount between standard and express shipping?
SELECT shipping_type, ROUND(AVG(purchase_amount),2) as "Average purchase amount"
FROM customertable
WHERE shipping_type IN ('Standard','Express')
GROUP BY shipping_type;

